    cursor: pointer;
}

.librarian-cross-icon {
    background-color: transparent;
    border: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #b3b3b3;
    cursor: pointer;
    padding: 4px;
}

.librarian-cross-icon:hover {
    color: #fff;
}

.librarian-paperplane-icon {
    border: none;
    background: #76B900;
    width: 36px;
    height: 36px;
    border-radius: 6px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    cursor: pointer;
    padding: 0;
