    <div> <script>
	
(function () {
  const $container = $('#loading-cards');
  const $firstchild = $container.find('.general-container');
  const $items = $firstchild.find('.nv-teaser');
  const $loadMoreBtn = $('#nv-show-load-more-btn');
  const itemsPerLoad = 3;
  let currentIndex = 0;

  function showItems() {
    $items.slice(currentIndex, currentIndex + itemsPerLoad).fadeIn();
    currentIndex += itemsPerLoad;

    if (currentIndex >= $items.length) {
      $loadMoreBtn.hide();
    }
  }

  // Hide all items initially
  $items.hide();

  // Show initial items
  showItems();

  $loadMoreBtn.on('click', showItems);
})();

</script></div>	

